class SessionTokenGenerator private constructor() {

    companion object {
        @Volatile
        private var instance: SessionTokenGenerator? = null

        fun getInstance(): SessionTokenGenerator {
            return instance ?: synchronized(this) {
                instance ?: SessionTokenGenerator().also { instance = it }
