        private const val SESSION_DURATION_MS = 24 * 60 * 60 * 1000L // 24 hours
        private const val API_TOKEN_DURATION_MS = 5 * 60 * 1000L // 5 minutes
        private const val ALPHANUMERIC_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    }

    private val secureRandom = SecureRandom()
    private var currentSessionToken: SessionToken? = null
    private val activeApiTokens = ConcurrentHashMap<String, SessionToken>()

    fun generateRandomString(length: Int = TOKEN_LENGTH): String {
        val sb = StringBuilder(length)
        for (i in 0 until length) {
            val index = secureRandom.nextInt(ALPHANUMERIC_CHARS.length)
            sb.append(ALPHANUMERIC_CHARS[index])
        }
        return sb.toString()
    }

