        invalidateSession()
        val token = generateRandomString()
        val sessionToken = SessionToken(
            token = token,
            expiresAt = System.currentTimeMillis() + SESSION_DURATION_MS,
            type = TokenType.SESSION
        )
        currentSessionToken = sessionToken
        return sessionToken
    }

    fun generateApiRequestToken(): SessionToken? {
        if (currentSessionToken == null || isTokenExpired(currentSessionToken!!)) {
