        val apiToken = SessionToken(
            token = token,
            expiresAt = System.currentTimeMillis() + API_TOKEN_DURATION_MS,
            type = TokenType.API_REQUEST
        )
        activeApiTokens[token] = apiToken
        return apiToken
    }

    fun getSessionId(): String? {
        val session = currentSessionToken ?: return null
        return if (!isTokenExpired(session)) {
            session.token
        } else {
            invalidateSession()
            null
        }
    }

    fun isSessionActive(): Boolean {
        val session = currentSessionToken ?: return false
        return !isTokenExpired(session)
    }

    fun validateApiToken(token: String): Boolean {
        val apiToken = activeApiTokens[token] ?: return false
        return if (!isTokenExpired(apiToken)) {
            true
        } else {
            activeApiTokens.remove(token)
            false
        }
    }

    fun consumeApiToken(token: String): Boolean {
        val apiToken = activeApiTokens.remove(token) ?: return false
        return !isTokenExpired(apiToken)
    }

    fun invalidateSession() {
        currentSessionToken = null
        activeApiTokens.clear()
    }

    fun invalidateApiToken(token: String) {
        activeApiTokens.remove(token)
    }

    fun getActiveApiTokenCount(): Int {
        cleanupExpiredApiTokens()
        return activeApiTokens.size
    }

