        return apiToken?.token
    }

    fun onApiRequestCompleted(token: String) {
        tokenGenerator.consumeApiToken(token)
    }

    fun isUserSessionValid(): Boolean {
        return tokenGenerator.isSessionActive()
    }

    fun onAppClosed() {
        tokenGenerator.invalidateSession()
    }

    fun getSessionDetails(): Map<String, Any?> {
        return tokenGenerator.getSessionInfo()
    }
}

